-- core
CREATE DATABASE IF NOT EXISTS "TELCO_LAB";
CREATE SCHEMA IF NOT EXISTS "TELCO_LAB"."TELCO_STAGE_LOAD";
CREATE SCHEMA IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE";
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."DATASET_DOMAIN" ALLOWED_VALUES 'telco' COMMENT = 'Business domain that owns the staged dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."DATA_PRODUCT" ALLOWED_VALUES 'telco_stage_seed' COMMENT = 'Logical data product name for the staged dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."SOURCE_SYSTEM" ALLOWED_VALUES 'telco_seed_generator' COMMENT = 'Source process that created the landed dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."OWNER_TEAM" ALLOWED_VALUES 'telco_data_platform' COMMENT = 'Engineering team accountable for the dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."STEWARD_TEAM" ALLOWED_VALUES 'telco_data_stewardship' COMMENT = 'Stewardship team accountable for metadata quality.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."SUPPORT_TEAM" ALLOWED_VALUES 'telco_operations' COMMENT = 'Operational team supporting the dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."LIFECYCLE" ALLOWED_VALUES 'sandbox', 'development', 'production' COMMENT = 'Dataset lifecycle state.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."REFRESH_CADENCE" ALLOWED_VALUES 'on_demand', 'daily', 'hourly' COMMENT = 'Expected refresh cadence for the dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."QUALITY_TIER" ALLOWED_VALUES 'bronze', 'silver', 'gold' COMMENT = 'Intended quality tier for the asset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."RETENTION_CLASS" ALLOWED_VALUES 'rolling_60_day_history', 'rolling_365_day_history' COMMENT = 'Retention posture for the dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."COMPLIANCE_ZONE" ALLOWED_VALUES 'internal', 'restricted' COMMENT = 'Internal usage zone for the dataset.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."SOURCE_ENTITY" ALLOWED_VALUES 'account', 'agreement', 'app_event', 'contact_medium', 'customer_interaction', 'device', 'geographic_address', 'individual', 'invoice', 'invoice_charge', 'party', 'party_role', 'payment', 'product_inventory', 'product_offering', 'resource', 'service', 'service_lifecycle_event', 'service_order', 'sim_card', 'subscription', 'trouble_ticket', 'usage_event' COMMENT = 'Source entity represented by the Snowflake table.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."RECORD_GRAIN" ALLOWED_VALUES 'entity_level', 'assignment_level', 'event_level', 'document_level' COMMENT = 'Business grain represented by each row.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."SEMANTIC_TYPE" ALLOWED_VALUES 'account_identifier', 'account_number', 'address_attribute', 'address_identifier', 'birth_date', 'category_code', 'charge_identifier', 'contact_identifier', 'contact_value', 'contract_identifier', 'created_timestamp', 'currency_amount', 'date_value', 'device_identifier', 'email_handle', 'event_identifier', 'event_timestamp', 'invoice_identifier', 'narrative_text', 'order_identifier', 'party_identifier', 'payment_identifier', 'person_name', 'phone_number', 'priority_code', 'product_attribute', 'product_identifier', 'resource_attribute', 'resource_identifier', 'role_identifier', 'role_type', 'service_identifier', 'sim_identifier', 'status_code', 'ticket_identifier', 'usage_measure' COMMENT = 'Business semantic attached to a column.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."SENSITIVITY" ALLOWED_VALUES 'internal_operational', 'public_synthetic', 'restricted_contact', 'restricted_identifier' COMMENT = 'Business-safe sensitivity label for a column.';
CREATE TAG IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."IDENTIFIER_ROLE" ALLOWED_VALUES 'descriptive', 'foreign_key', 'natural_key', 'primary_key' COMMENT = 'Relational role of the column.';
CREATE CONTACT IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."TELCO_ACCESS_APPROVALS" EMAIL_DISTRIBUTION_LIST = 'access.approvals@example.com' COMMENT = 'Contact for access approval decisions on staged telco data.';
CREATE CONTACT IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."TELCO_SECURITY_COMPLIANCE" EMAIL_DISTRIBUTION_LIST = 'security.compliance@example.com' COMMENT = 'Contact for governance and compliance questions on staged telco data.';
CREATE CONTACT IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."TELCO_DATA_STEWARDS" EMAIL_DISTRIBUTION_LIST = 'data.stewards@example.com' COMMENT = 'Contact for metadata stewardship and glossary alignment.';
CREATE CONTACT IF NOT EXISTS "TELCO_LAB"."TELCO_GOVERNANCE"."TELCO_SUPPORT" EMAIL_DISTRIBUTION_LIST = 'telco.support@example.com' COMMENT = 'Contact for operational support and issue triage.';

-- schema
COMMENT ON SCHEMA "TELCO_LAB"."TELCO_STAGE_LOAD" IS 'Snowflake landing schema for deterministic telco seed files. Tables in this schema preserve source-shaped records for downstream staging in dbt and governance demonstrations in Horizon.
';
